/**
 * Convert an ISO 3166-1 alpha-2 code to a flag emoji.
 * Each letter is mapped to a Regional Indicator Symbol (U+1F1E6–U+1F1FF).
 */
function isoToFlag(iso) {
  return [...iso.toUpperCase()]
    .map((c) => String.fromCodePoint(0x1f1e6 + c.charCodeAt(0) - 65))
    .join("");
}

/**
 * Flags for non-sovereign entities whose emoji flags are not derivable
 * from a standard ISO 3166-1 alpha-2 code.
 */
const SPECIAL_FLAGS = {
  "england": "🏴󠁧󠁢󠁥󠁮󠁧󠁿",
  "scotland": "🏴󠁧󠁢󠁳󠁣󠁴󠁿",
  "wales": "🏴󠁧󠁢󠁷󠁬󠁳󠁿",
};

